 1	import React, { FC, memo, useState } from 'react';
 2	
 3	import { Action } from '@openshift-console/dynamic-plugin-sdk';
 4	import { Dropdown, DropdownList } from '@patternfly/react-core';
 5	import DropdownToggle from '@utils/components/Toggles/DropdownToggle';
 6	import KebabToggle from '@utils/components/Toggles/KebabToggle';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	
 9	import ActionDropdownItem from '../ActionDropdownItem/ActionDropdownItem';
10	
11	type ActionsDropdownProps = {
12	  actions: Action[];
13	  className?: string;
14	  id?: string;
15	  isKebabToggle?: boolean;
16	  onLazyClick?: () => void;
17	};
18	
19	const ActionsDropdown: FC<ActionsDropdownProps> = ({
20	  actions = [],
21	  className,
22	  id,
23	  isKebabToggle,
24	  onLazyClick,
25	}) => {
26	  const { t } = useNetworkingTranslation();
27	  const [isOpen, setIsOpen] = useState(false);
28	
29	  const onToggle = () => {
30	    setIsOpen((prevIsOpen) => {
31	      if (onLazyClick && !prevIsOpen) onLazyClick();
32	
33	      return !prevIsOpen;
34	    });
35	  };
36	
37	  const Toggle = isKebabToggle
38	    ? KebabToggle({ isExpanded: isOpen, onClick: onToggle })
39	    : DropdownToggle({
40	        children: t('Actions'),
41	        isExpanded: isOpen,
42	        onClick: onToggle,
43	      });
44	
45	  return (
46	    <Dropdown
47	      className={className}
48	      data-test-id={id}
49	      isOpen={isOpen}
50	      onOpenChange={(open: boolean) => setIsOpen(open)}
51	      popperProps={{ enableFlip: true, position: 'right' }}
52	      toggle={Toggle}
53	    >
54	      <DropdownList>
55	        {actions?.map((action) => (
56	          <ActionDropdownItem action={action} key={action?.id} setIsOpen={setIsOpen} />
57	        ))}
58	      </DropdownList>
59	    </Dropdown>
60	  );
61	};
62	
63	export default memo(ActionsDropdown);

